<?php namespace App\Domains\Auto\Services; class VehicleService { public function create(array $data) { return \App\Domains\Auto\Models\Vehicle::create($data); } public function update($id, array $data) { $vehicle = \App\Domains\Auto\Models\Vehicle::find($id); return $vehicle ? $vehicle->update($data) : false; } public function delete($id) { return \App\Domains\Auto\Models\Vehicle::destroy($id); } public function list($tenantId) { return \App\Domains\Auto\Models\Vehicle::where('tenant_id', $tenantId)->get(); } }
